(8, 3, '2026-05-12', 0.00, 0.00, '2026-05-12 15:34:16', '{\"ok\":true,\"plan\":{\"plan\":[{\"dia\":\"lunes\",\"desayuno\":{\"nombre\":\"Tortillas de Harina con Guacamole\",\"ingredientes\":[\"4 Tortillas de Harina Mexicanas\",\"1/2 taza de Guacamole Con Tomate Y Pimiento Pacose\"],\"preparacion\":\"1. Calentar las tortillas de harina en una sartén durante 30 segundos por cada lado.\\n2. Untar una capa de guacamole en cada tortilla.\\n3. Doblar las tortillas por la mitad y servir.\"},\"almuerzo\":{\"nombre\":\"Mini Tacos\",\"ingredientes\":[\"6 Tortillas De Maíz Para Mini Tacos Maxipan\",\"1/2 taza de Proteína De Trigo En Forma De Milanesa Cordon green\",\"1/4 taza de Crema Agria Pacose\"],\"preparacion\":\"1. Calentar las tortillas de maíz en una sartén durante 30 segundos por cada lado.\\n2. Rellenar cada tortilla con la proteína de trigo y una cucharada de crema agria.\\n3. Servir inmediatamente.\"},\"cena\":{\"nombre\":\"Pollo Horneado con Salchicha de Soya\",\"ingredientes\":[\"200g de Pollo Horneado Receta Oriental Supermaxi\",\"1 Salchicha De Soya Con Chía Orégano Albahaca Cordon green\"],\"preparacion\":\"1. Precalentar el horno a 180°C.\\n2. Hornear el pollo durante 20 minutos.\\n3. Asar la salchicha de soya en una sartén durante 5 minutos por cada lado.\\n4. Servir el pollo con la salchicha de soya.\"}},{\"dia\":\"martes\",\"desayuno\":{\"nombre\":\"Waffles de Vainilla\",\"ingredientes\":[\"1 paquete de Waffles De Vainilla Gout\"],\"preparacion\":\"1. Calentar los waffles según las instrucciones del paquete.\\n2. Servir con frutas frescas o sirope de arce.\"},\"almuerzo\":{\"nombre\":\"Tortas de Queso\",\"ingredientes\":[\"4 Tortillas De Harina De Trigo Integral\",\"2 rebanadas de Queso Cheddar Block Vegano Daiya\"],\"preparacion\":\"1. Calentar una sartén a fuego medio.\\n2. Colocar una tortilla en la sartén y espolvorear con queso.\\n3. Doblar la tortilla por la mitad y cocinar durante 2 minutos.\\n4. Voltear y cocinar durante otros 2 minutos.\"},\"cena\":{\"nombre\":\"Pizza Casera\",\"ingredientes\":[\"1 paquete de Masa Para Pizza Clásica Santa Cruz\",\"1/2 taza de salsa de tomate\",\"1 taza de queso rallado\"],\"preparacion\":\"1. Precalentar el horno a 220°C.\\n2. Estirar la masa para pizza en un círculo.\\n3. Untar la salsa de tomate en la masa.\\n4. Espolvorear el queso rallado sobre la salsa.\\n5. Hornear durante 15 minutos.\"}},{\"dia\":\"miercoles\",\"desayuno\":{\"nombre\":\"Tortillas de Harina con Hamburguesa de Soya\",\"ingredientes\":[\"4 Tortillas de Harina Mexicanas\",\"2 Hamburguesa Soya Y Lenteja Cordon green\"],\"preparacion\":\"1. Calentar las tortillas de harina en una sartén durante 30 segundos por cada lado.\\n2. Cocinar las hamburguesas de soya en una sartén durante 3 minutos por cada lado.\\n3. Colocar una hamburguesa en cada tortilla y servir.\"},\"almuerzo\":{\"nombre\":\"Ensalada de Pollo\",\"ingredientes\":[\"200g de Pollo Horneado Receta Oriental Supermaxi\",\"1 taza de lechuga picada\",\"1 taza de tomate picado\"],\"preparacion\":\"1. Cortar el pollo en trozos pequeños.\\n2. Mezclar el pollo con la lechuga y el tomate en un tazón.\\n3. Aderezar con vinagreta y servir.\"},\"cena\":{\"nombre\":\"Lomo de Cerdo Horneado\",\"ingredientes\":[\"200g de Lomo De Cerdo Hornado Gourmand Al Peso\"],\"preparacion\":\"1. Precalentar el horno a 180°C.\\n2. Hornear el lomo de cerdo durante 20 minutos.\\n3. Servir con puré de papas y vegetales al vapor.\"}},{\"dia\":\"jueves\",\"desayuno\":{\"nombre\":\"Tortillas de Maíz con Guacamole\",\"ingredientes\":[\"6 Tortillas De Maíz Para Mini Tacos Maxipan\",\"1/2 taza de Guacamole Con Tomate Y Pimiento Pacose\"],\"preparacion\":\"1. Calentar las tortillas de maíz en una sartén durante 30 segundos por cada lado.\\n2. Untar una capa de guacamole en cada tortilla.\\n3. Doblar las tortillas por la mitad y servir.\"},\"almuerzo\":{\"nombre\":\"Sándwich de Queso\",\"ingredientes\":[\"2 Tortillas De Harina De Trigo Integral\",\"2 rebanadas de Queso Cheddar Block Vegano Daiya\"],\"preparacion\":\"1. Calentar una sartén a fuego medio.\\n2. Colocar una tortilla en la sartén y espolvorear con queso.\\n3. Doblar la tortilla por la mitad y cocinar durante 2 minutos.\\n4. Voltear y cocinar durante otros 2 minutos.\"},\"cena\":{\"nombre\":\"Pollo Horneado con Vegetales\",\"ingredientes\":[\"200g de Pollo Horneado Receta Oriental Supermaxi\",\"1 taza de brócoli al vapor\"],\"preparacion\":\"1. Precalentar el horno a 180°C.\\n2. Hornear el pollo durante 20 minutos.\\n3. Servir con brócoli al vapor y puré de papas.\"}},{\"dia\":\"viernes\",\"desayuno\":{\"nombre\":\"Waffles de Vainilla con Frutas\",\"ingredientes\":[\"1 paquete de Waffles De Vainilla Gout\",\"1 taza de frutas frescas\"],\"preparacion\":\"1. Calentar los waffles según las instrucciones del paquete.\\n2. Servir con frutas frescas y sirope de arce.\"},\"almuerzo\":{\"nombre\":\"Tortas de Hamburguesa de Soya\",\"ingredientes\":[\"4 Tortillas De Harina De Trigo Integral\",\"2 Hamburguesa Soya Y Lenteja Cordon green\"],\"preparacion\":\"1. Calentar una sartén a fuego medio.\\n2. Cocinar las hamburguesas de soya en la sartén durante 3 minutos por cada lado.\\n3. Colocar una hamburguesa en cada tortilla y servir.\"},\"cena\":{\"nombre\":\"Lomo de Cerdo Horneado con Puré de Papas\",\"ingredientes\":[\"200g de Lomo De Cerdo Hornado Gourmand Al Peso\",\"2 papas grandes\"],\"preparacion\":\"1. Precalentar el horno a 180°C.\\n2. Hornear el lomo de cerdo durante 20 minutos.\\n3. Hacer puré de papas y servir con el lomo de cerdo.\"}}],\"lista_compras\":{\"aki\":[{\"nombre\":\"Guacamole Con Tomate Y Pimiento Hortilisto\",\"precio\":1.66},{\"nombre\":\"Tortillas De Harina Mexicanas\",\"precio\":1.83},{\"nombre\":\"Proteína De Trigo En Forma De Milanesa Cordon green\",\"precio\":1.89},{\"nombre\":\"Crema Agria Pacose\",\"precio\":2.17},{\"nombre\":\"Waffles De Vainilla Gout\",\"precio\":3.07},{\"nombre\":\"Jugo De Naranja Akí\",\"precio\":2.31},{\"nombre\":\"No Es Queso Vegano Tipo Cheddar