(21, 3, '2026-05-12', 14.71, 13.64, '2026-05-12 15:49:36', '{\"plan\":[{\"dia\":\"lunes\",\"desayuno\":{\"nombre\":\"Plátano Maduro Fresco con Kiwi\",\"ingredientes\":[\"2 unidades de Plátano Maduro Fresco\",\"1 unidad de Kiwi\"],\"preparacion\":\"1. Pelar los plátanos y cortarlos en rodajas.\\n2. Pelar el kiwi y cortarlo en rodajas.\\n3. Servir juntos.\"},\"almuerzo\":{\"nombre\":\"Tilapia a la Parrilla con Ensalada de Uva\",\"ingredientes\":[\"150g de Tilapia Filete Fresco\",\"100g de Uva Roja Sin Semilla\",\"1 cucharada de aceite de oliva\"],\"preparacion\":\"1. Precalentar la parrilla.\\n2. Sazonar la tilapia con sal y pimienta.\\n3. Cocinar la tilapia durante 4 minutos por lado.\\n4. Mezclar la uva con aceite de oliva y servir como ensalada.\"},\"cena\":{\"nombre\":\"Sopa de Mariscos con Camarones\",\"ingredientes\":[\"200g de Camarones Pelados y Desvenados Medianos\",\"1 cucharada de aceite de oliva\",\"1 cebolla picada\"],\"preparacion\":\"1. Calentar el aceite en una olla.\\n2. Agregar la cebolla picada y cocinar hasta que esté suave.\\n3. Agregar los camarones y cocinar durante 2 minutos.\\n4. Agregar caldo de pescado y cocinar durante 5 minutos.\"}},{\"dia\":\"martes\",\"desayuno\":{\"nombre\":\"Babaco Fresco con Manzana\",\"ingredientes\":[\"1 unidad de Babaco Fresco\",\"1 unidad de Manzana Gala Del Sur\"],\"preparacion\":\"1. Pelar el babaco y cortarlo en rodajas.\\n2. Cortar la manzana en rodajas.\\n3. Servir juntos.\"},\"almuerzo\":{\"nombre\":\"Nuggets de Pescado con Ensalada de Lechuga\",\"ingredientes\":[\"100g de Nuggets De Pescado Plumrose\",\"1 cucharada de aceite de oliva\",\"1 lechuga picada\"],\"preparacion\":\"1. Calentar el aceite en una sartén.\\n2. Agregar los nuggets de pescado y cocinar durante 3 minutos por lado.\\n3. Mezclar la lechuga con aceite de oliva y servir como ensalada.\"},\"cena\":{\"nombre\":\"Corvina Blanca al Horno con Puré de Maracuyá\",\"ingredientes\":[\"150g de Corvina Blanca Maramar Akí\",\"1 cucharada de aceite de ol