(24, 3, '2026-05-12', 0.00, 0.00, '2026-05-12 15:49:36', '{\"plan\":[{\"dia\":\"lunes\",\"desayuno\":{\"nombre\":\"Tostada de pan integral con mermelada\",\"ingredientes\":[\"2 rebanadas de Pan Tostado Integral La Estrella\",\"1 cucharada de mermelada\"],\"preparacion\":\"1. Tostar el pan integral en una tostadora o en una sartén con un poco de aceite.\\n2. Untar la mermelada sobre las rebanadas de pan tostado.\"},\"almuerzo\":{\"nombre\":\"Sandwich de jamón y queso\",\"ingredientes\":[\"2 rebanadas de Pan Integral Akí\",\"2 lonchas de jamón\",\"1 loncha de queso\"],\"preparacion\":\"1. Colocar una loncha de jamón y una loncha de queso sobre una rebanada de pan.\\n2. Cubrir con la otra rebanada de pan.\"},\"cena\":{\"nombre\":\"Pan con chocolate\",\"ingredientes\":[\"1 rebanada de Pan Integral Akí\",\"1 cucharada de chocolate\"],\"preparacion\":\"1. Calentar el chocolate en el microondas durante 10 segundos.\\n2. Untar el chocolate sobre la rebanada de pan.\"}},{\"dia\":\"martes\",\"desayuno\":{\"nombre\":\"Galletas con leche\",\"ingredientes\":[\"2 galletas de Galletas De Dulce Artesanales Arenilla Vekar lematehu\",\"1 taza de leche\"],\"preparacion\":\"1. Verter la leche en un tazón.\\n2. Sumergir las galletas en la leche.\"},\"almuerzo\":{\"nombre\":\"Sandwich de pavo y aguacate\",\"ingredientes\":[\"2 rebanadas de Pan Integral Rebanado Tradicional Cyrano\",\"2 lonchas de pavo\",\"1/2 aguacate\"],\"preparacion\":\"1. Colocar una loncha de pavo y media aguacate sobre una rebanada de pan.\\n2. Cubrir con la otra rebanada de pan.\"},\"cena\":{\"nombre\":\"Tostada de pan con queso\",\"ingredientes\":[\"2 rebanadas de Pan Tostado Integral La Estrella\",\"1 loncha de queso\"],\"preparacion\":\"1. Tostar el pan integral en una tostadora o en una sartén con un poco de aceite.\\n2. Colocar la loncha de queso sobre la rebanada de pan tostado.\"}},{\"dia\":\"miercoles\",\"desayuno\":{\"nombre\":\"Pan con mantequilla y mermelada\",\"ingredientes\":[\"2 rebanadas de Pan Integral Akí\",\"1 cucharada de mantequilla\",\"1 cucharada de mermelada\"],\"preparacion\":\"1. Untar la mantequilla sobre las rebanadas de pan.\\n2. Untar la mermelada sobre la mantequilla.\"},\"almuerzo\":{\"nombre\":\"Sandwich de atun y lechuga\",\"ingredientes\":[\"2 rebanadas de Pan Integral Rebanado Tradicional Cyrano\",\"1 lata de atun\",\"1 lechuga\"],\"preparacion\":\"1. Colocar la lata de atun sobre una rebanada de pan.\\n2. Agregar la lechuga y cubrir con la otra rebanada de pan.\"},\"cena\":{\"nombre\":\"Galletas con chocolate\",\"ingredientes\":[\"2 galletas de Galletas De Dulce Artesanales Arenilla Vekar lematehu\",\"1 cucharada de chocolate\"],\"preparacion\":\"1. Calentar el chocolate en el microondas durante 10 segundos.\\n2. Untar el chocolate sobre las galletas.\"}},{\"dia\":\"jueves\",\"desayuno\":{\"nombre\":\"Tostada de pan con aguacate\",\"ingredientes\":[\"2 rebanadas de Pan Tostado Integral La Estrella\",\"1/2 aguacate\"],\"preparacion\":\"1. Tostar el pan integral en una tostadora o en una sartén con un poco de aceite.\\n2. Colocar el aguacate sobre la rebanada de pan tostado.\"},\"almuerzo\":{\"nombre\":\"Sandwich de pollo y tomate\",\"ingredientes\":[\"2 rebanadas de Pan Integral Akí\",\"2 lonchas de pollo\",\"1 tomate\"],\"preparacion\":\"1. Colocar una loncha de pollo y un tomate sobre una rebanada de pan.\\n2. Cubrir con la otra rebanada de pan.\"},\"cena\":{\"nombre\":\"Pan con queso y jamon\",\"ingredientes\":[\"2 rebanadas de Pan Integral Rebanado Tradicional Cyrano\",\"1 loncha de queso\",\"1 loncha de jamon\"],\"preparacion\":\"1. Colocar la loncha de queso y la loncha de jamon sobre una rebanada de pan.\\n2. Cubrir con la otra rebanada de pan.\"}},{\"dia\":\"viernes\",\"desayuno\":{\"nombre\":\"Galletas con leche y frutas\",\"ingredientes\":[\"2 galletas de Galletas De Dulce Artesanales Arenilla Vekar lematehu\",\"1 taza de leche\",\"1 fruta\"],\"preparacion\":\"1. Verter la leche en un tazón.\\n2. Sumergir las galletas en la leche y agregar la fruta.\"},\"almuerzo\":{\"nombre\":\"Sandwich de carne y lechuga\",\"ingredientes\":[\"2 rebanadas de Pan Integral Akí\",\"2 lonchas de carne\",\"1 lechuga\"],\"preparacion\":\"1. Colocar una loncha de carne y una lechuga sobre una rebanada de pan.\\n2. Cubrir con la otra rebanada de pan.\"},\"cena\":{\"nombre\":\"Tostada de pan con mantequilla y mermelada\",\"ingredientes\":[\"2 rebanadas de Pan Tostado Integral La Estrella\",\"1 cucharada de mantequilla\",\"1 cucharada de mermelada\"],\"preparacion\":\"1. Tostar el pan integral en una tostadora o en una sartén con un poco de aceite.\\n2. Untar la mantequilla y la mermelada sobre la rebanada de pan tostado.\"}}],\"lista_compras\":{\"aki\":[\"Pan Integral Akí\",\"Pan Tostado Integral La Estrella\",\"Galletas De Dulce Artesanales Arenilla Vekar lematehu\"],\"supermaxi\":[\"Pan Integral Rebanado Tradicional Cyrano\",\"Pan Yogurt Y Nueces Supermaxi\"]},\"ahorro_estimado\":10,\"consejo\":\"Es importante tener una variedad de ingredientes en la despensa para poder preparar diferentes comidas.\",\"fechaGeneracion\":\"2026-05-09T03:15:02.427Z\"}'),
(25, 3, '2026-05-12', 0.00, 0.00, '2026-05-12 15:49:36', '{\"plan\":[{\"dia\":\"lunes\",\"desayuno\":{\"nombre\":\"Tortilla de verduras\",\"ingredientes\":[\"2 huevos\",\"100g de zanahoria blanca\",\"50g de cebolla larga\"],\"preparacion\":\"1. Pela la zanahoria y la cebolla y córtalas en trozos pequeños.\\n2. Bate los huevos y mezcla con las verduras.\\n3. Calienta una sartén con un poco de aceite y cocina la mezcla de huevos y verduras.\"},\"almuerzo\":{\"nombre\":\"Pollo con ensalada\",\"ingredientes\":[\"150g de pollo pavo\",\"1/2 taza de ensalada tropical\",\"50g de lechuga romana\"],\"preparacion\":\"1. Cocina el pollo al vapor.\\n2. Mezcla la ensalada tropical con la lechuga romana.\\n3. Sirve el pollo con la ensalada.\"},\"cena\":{\"nombre\":\"Sopa de verduras\",\"ingredientes\":[\"200g de champiñones\",\"100g de zanahoria blanca\",\"50g de cebolla larga\"],\"preparacion\":\"1. Pela la zanahoria y la cebolla y córtalas en trozos pequeños.\\n2. Calienta una sartén con un poco de aceite y cocina los champiñones y las verduras.\\n3. Vierte agua hirviendo y cocina durante 15 minutos.\"}},{\"dia\":\"martes\",\"desayuno\":{\"nombre\":\"Tostada de aguacate\",\"ingredientes\":[\"1 aguacate\",\"2 rebanadas de pan\",\"sal y pimienta\"],\"preparacion\":\"1. Corta el aguacate en trozos pequeños.\\n2. Coloca el aguacate en una tostada de pan.\\n3. Agrega sal y pimienta al gusto.\"},\"almuerzo\":{\"nombre\":\"Pollo con ensalada de tomate\",\"ingredientes\":[\"150g de pollo pavo\",\"1/2 taza de tomate cherry\",\"50g de lechuga romana\"],\"preparacion\":\"1. Cocina el pollo al vapor.\\n2. Mezcla el tomate cherry con la lechuga romana.\\n3. Sirve el pollo con la ensalada de tomate.\"},\"cena\":{\"nombre\":\"Salsa de aguacate\",\"ingredientes\":[\"2 aguacates\",\"1 cebolla larga\",\"sal y pimienta\"],\"preparacion\":\"1. Corta los aguacates en trozos pequeños.\\n2. Pela la cebolla y córtala en trozos pequeños.\\n3. Mezcla los aguacates con la cebolla y agrega sal y pimienta al gusto.\"}},{\"dia\":\"miércoles\",\"desayuno\":{\"nombre\":\"Tortilla de espinacas\",\"ingredientes\":[\"2 huevos\",\"100g de espinacas\",\"50g de cebolla larga\"],\"preparacion\":\"1. Pela la cebolla y córtala en trozos pequeños.\\n2. Bate los huevos y mezcla con las espinacas y la cebolla.\\n3. Calienta una sartén con un poco de aceite y cocina la mezcla de huevos y espinacas.\"},\"almuerzo\":{\"nombre\":\"Pollo con arroz\",\"ingredientes\":[\"150g de pollo pavo\",\"1/2 taza de arroz\",\"50g de lechuga romana\"],\"preparacion\":\"1. Cocina el pollo al vapor.\\n2. Cocina el arroz según las instrucciones del paquete.\\n3. Mezcla el pollo con el arroz y la lechuga romana.\"},\"cena\":{\"nombre\":\"Sopa de pollo\",\"ingredientes\":[\"200g de pollo pavo\",\"100g de zanahoria blanca\",\"50g de cebolla larga\"],\"preparacion\":\"1. Pela la zanahoria y la cebolla y córtalas en trozos pequeños.\\n2. Calienta una sartén con un poco de aceite y cocina el pollo y las verduras.\\n3. Vierte agua hirviendo y cocina durante 15 minutos.\"}},{\"dia\":\"jueves\",\"desayuno\":{\"nombre\":\"Tostada de aguacate\",\"ingredientes\":[\"1 aguacate\",\"2 rebanadas de pan\",\"sal y pimienta\"],\"preparacion\":\"1. Corta el aguacate en trozos pequeños.\\n2. Coloca el aguacate en una tostada de pan.\\n3. Agrega sal y pimienta al gusto.\"},\"almuerzo\":{\"nombre\":\"Pollo con ensalada de lechuga\",\"ingredientes\":[\"150g de pollo pavo\",\"1/2 taza de lechuga romana\",\"50g de tomate cherry\"],\"preparacion\":\"1. Cocina el pollo al vapor.\\n2. Mezcla la lechuga romana con el tomate cherry.\\n3. Sirve el pollo con la ensalada de lechuga.\"},\"cena\":{\"nombre\":\"Salsa de aguacate\",\"ingredientes\":[\"2 aguacates\",\"1 cebolla larga\",\"sal y pimienta\"],\"preparacion\":\"1. Corta los aguacates en trozos pequeños.\\n2. Pela la cebolla y córtala en trozos pequeños.\\n3. Mezcla los aguacates con la cebolla y agrega sal y pimienta al gusto.\"}},{\"dia\":\"viernes\",\"desayuno\":{\"nombre\":\"Tortilla de espinacas\",\"ingredientes\":[\"2 huevos\",\"100g de espinacas\",\"50g de cebolla larga\"],\"preparacion\":\"1. Pela la cebolla y córtala en trozos pequeños.\\n2. Bate los huevos y mezcla con las espinacas y la cebolla.\\n3. Calienta una sartén con un poco de aceite y cocina la mezcla de huevos y espinacas.\"},\"almuerzo\":{\"nombre\":\"Pollo con arroz\",\"ingredientes\":[\"150g de pollo pavo\",\"1/2 taza de arroz\",\"50g de lechuga romana\"],\"preparacion\":\"1. Cocina el pollo al vapor.\\n2. Cocina el arroz según las instrucciones del paquete.\\n3. Mezcla el pollo con el arroz y la lechuga romana.\"},\"cena\":{\"nombre\":\"Sopa de pollo\",\"ingredientes\":[\"200g de pollo pavo\",\"100g de zanahoria blanca\",\"50g de cebolla larga\"],\"preparacion\":\"1. Pela la zanahoria y la cebolla y córtalas en trozos pequeños.\\n2. Calienta una sartén con un poco de aceite y cocina el pollo y las verduras.\\n3. Vierte agua hirviendo y cocina durante 15 minutos.\"}}],\"lista_compras\":{\"aki\":[\"leche\",\"huevos\",\"pan\",\"carnicería\",\"frutas\",\"verduras\"],\"supermaxi\":[\"arroz\",\"sal\",\"pimienta\",\"aceite\",\"salsa de tomate\",\"mayonesa\"]},\"ahorro_estimado\":10,\"consejo\":\"Recuerda utilizar ingredientes frescos y de temporada para mejorar el sabor y la calidad de las comidas.\",\"fechaGeneracion\":\"2026-05-08T02:28:49.311Z\"}'),
(26, 3, '2026-05-12', 0.00, 0.00, '2026-05-12 15:49:36', '{\"plan\":[{\"dia\":\"lunes\",\"desayuno\":{\"nombre\":\"Tostadas con frijoles y queso\",\"ingredientes\":[\"4 tortillinas clásica bimbo\",\"1 taza de frijoles negros cocidos\",\"2 cucharadas de queso rallado\"],\"preparacion\":\"1. Calentar las tortillinas en una sartén.\\n2. Colocar frijoles negros cocidos encima de las tortillinas.\\n3. Cubrir con queso rallado.\"},\"almuerzo\":{\"nombre\":\"Hamburguesas caseras con papas fritas\",\"ingredientes\":[\"4 pan para hamburguesa supermaxi\",\"8 oz de carne molida\",\"2 papas medianas\",\"aceite vegetal\"],\"preparacion\":\"1. Precalentar la parrilla.\\n2. Formar hamburguesas con la carne molida.\\n3. Cocinar las hamburguesas en la parrilla.\\n4. Cortar las papas en rodajas.\\n5. Freír las papas en aceite vegetal hasta que estén doradas.\"},\"cena\":{\"nombre\":\"Ensalada de frutas con granola\",\"ingredientes\":[\"1 taza de granola\",\"1 taza de frutas frescas (frutillas, naranjas, plátanos)\",\"2 cucharadas de miel\"],\"preparacion\":\"1. Mezclar la granola con las frutas frescas en un tazón.\\n2. Agregar la miel y mezclar bien.\"}},{\"dia\":\"martes\",\"desayuno\":{\"nombre\":\"Tortillas con queso y huevo\",\"ingredientes\":[\"4 tortillas de maíz\",\"4 huevos\",\"2 cucharadas de queso rallado\"],\"preparacion\":\"1. Calentar las tortillas en una sartén.\\n2. Colocar un huevo revuelto encima de cada tortilla.\\n3. Cubrir con queso rallado.\"},\"almuerzo\":{\"nombre\":\"Pollo a la parrilla con ensalada de lechuga\",\"ingredientes\":[\"4 pechugas de pollo\",\"2 tazas de lechuga fresca\",\"1 taza de tomate fresco\"],\"preparacion\":\"1. Precalentar la parrilla.\\n2. Marinar el pollo en una mezcla de aceite, vinagre y especias.\\n3. Cocinar el pollo en la parrilla.\\n4. Mezclar la lechuga fresca y el tomate fresco en un tazón.\"},\"cena\":{\"nombre\":\"Sopa de verduras con pan crujiente\",\"ingredientes\":[\"2 tazas de verduras frescas (calabacín, zanahoria, cebolla)\",\"4 rebanadas de pan integral\"],\"preparacion\":\"1. Calentar aceite en una sartén.\\n2. Agregar las verduras frescas y cocinar hasta que estén tiernas.\\n3. Agregar agua y cocinar hasta que la sopa esté caliente.\\n4. Freír las rebanadas de pan integral en aceite hasta que estén crujientes.\"}},{\"dia\":\"miércoles\",\"desayuno\":{\"nombre\":\"Fruta fresca con granola\",\"ingredientes\":[\"1 taza de fruta fresca (naranjas, plátanos, frutillas)\",\"1 taza de granola\"],\"preparacion\":\"1. Mezclar la fruta fresca con la granola en un tazón.\"},\"almuerzo\":{\"nombre\":\"Huevos revueltos con espinacas\",\"ingredientes\":[\"4 huevos\",\"1 taza de espinacas frescas\"],\"preparacion\":\"1. Calentar aceite en una sartén.\\n2. Agregar las espinacas frescas y cocinar hasta que estén tiernas.\\n3. Agregar los huevos y revolver hasta que estén cocidos.\"},\"cena\":{\"nombre\":\"Tortitas de maíz con frijoles y queso\",\"ingredientes\":[\"4 tortillas de maíz\",\"1 taza de frijoles negros cocidos\",\"2 cucharadas de queso rallado\"],\"preparacion\":\"1. Calentar las tortillas en una sartén.\\n2. Colocar frijoles negros cocidos encima de cada tortilla.\\n3. Cubrir con queso rallado.\"}},{\"dia\":\"jueves\",\"desayuno\":{\"nombre\":\"Tostadas con aguacate y huevo\",\"ingredientes\":[\"4 tortillinas clásica bimbo\",\"2 aguacates maduros\",\"2 huevos\"],\"preparacion\":\"1. Calentar las tortillinas en una sartén.\\n2. Colocar un aguacate maduro encima de cada tortilla.\\n3. Agregar un huevo revuelto encima del aguacate.\"},\"almuerzo\":{\"nombre\":\"Pollo a la parrilla con ensalada de tomate\",\"ingredientes\":[\"4 pechugas de pollo\",\"2 tazas de tomate fresco\"],\"preparacion\":\"1. Precalentar la parrilla.\\n2. Marinar el pollo en una mezcla de aceite, vinagre y especias.\\n3. Cocinar el pollo en la parrilla.\\n4. Mezclar el tomate fresco en un tazón.\"},\"cena\":{\"nombre\":\"Sopa de lentejas con pan crujiente\",\"ingredientes\":[\"2 tazas de lentejas cocidas\",\"4 rebanadas de pan integral\"],\"preparacion\":\"1. Calentar aceite en una sartén.\\n2. Agregar las lentejas cocidas y cocinar hasta que estén calientes.\\n3. Agregar agua y cocinar hasta que la sopa esté caliente.\\n4. Freír las rebanadas de pan integral en aceite hasta que estén crujientes.\"}},{\"dia\":\"viernes\",\"desayuno\":{\"nombre\":\"Tortitas de maíz con frijoles y queso\",\"ingredientes\":[\"4 tortillas de maíz\",\"1 taza de frijoles negros cocidos\",\"2 cucharadas de queso rallado\"],\"preparacion\":\"1. Calentar las tortillas en una sartén.\\n2. Colocar frijoles negros cocidos encima de cada tortilla.\\n3. Cubrir con queso rallado.\"},\"almuerzo\":{\"nombre\":\"Hamburguesas caseras con papas fritas\",\"ingredientes\":[\"4 pan para hamburguesa supermaxi\",\"8 oz de carne molida\",\"2 papas medianas\",\"aceite vegetal\"],\"preparacion\":\"1. Precalentar la parrilla.\\n2. Formar hamburguesas con la carne molida.\\n3. Cocinar las hamburguesas en la parrilla.\\n4. Cortar las papas en rodajas.\\n5. Freír las papas en aceite vegetal hasta que estén doradas.\"},\"cena\":{\"nombre\":\"Ensalada de frutas con granola\",\"ingredientes\":[\"1 taza de fruta fresca (naranjas, plátanos, frutillas)\",\"1 taza de granola\"],\"preparacion\":\"1. Mezclar la fruta fresca con la granola en un tazón.\"}}],\"lista_compras\":{\"aki\":[\"tortillas de maíz\",\"frijoles negros\",\"queso rallado\"],\"supermaxi\":[\"pan para hamburguesa\",\"carne molida\",\"papas\",\"aceite vegetal\"]},\"ahorro_estimado\":10,\"consejo\":\"Recuerda utilizar ingredientes frescos y de temporada para obtener el mejor sabor.\",\"fechaGeneracion\":\"2026-05-08T02:24:50.885Z\"}');
