INSERT INTO `recetas` (`id`, `usuario_id`, `nombre`, `descripcion`, `porciones`, `tiempo_min`, `categoria`) VALUES
(5, 1, 'Pollo relleno envuelto en tocino', 'Ingredientes:\n- 4 pechugas de pollo deshuesadas y sin piel\n- 8 lonchas de tocino\n- 1 taza de espinacas frescas\n- 1 taza de queso rallado mozzarella\n\nPreparación:\n1. Precalienta el horno a 200° C.\n2. Abre las pechugas de pollo a la mitad sin separarlas por completo para formar un bolsillo.\n3. Rellena cada pechuga con espinacas frescas y queso rallado.\n4. Cierra las pechugas y envuélvelas firmemente con rebanadas de tocino.\n5. Sazona con sal y pimienta al gusto.\n6. Coloca las pechugas rellenas en una bandeja para hornear y hornea durante 25-30 minutos, o hasta que el pollo esté cocido y el tocino esté crujiente.', 4, 25, 'ph-fork-knife'),
(6, 1, 'Pescado frito con patacones', 'Ingredientes:\n- 4 filetes de pescado\n- 2 plátanos verdes\n- 1 cebolla\n- 2 dientes de ajo\n- 1 limón\n\nPreparación:\n1. Sazonar el pescado con sal, pimienta, ajo y cebolla.\n2. Dejar marinar en la refrigeradora por una hora.\n3. Freír el pescado en aceite caliente.\n4. Preparar los patacones fritos.\n5. Servir el pescado caliente sobre una cama de patacones.', 4, 60, 'ph-hamburger'),
(7, 3, 'Pastel de Chocolate', 'Ingredientes:\n- 2 tazas de harina de trigo\n- 1 y 3/4 tazas de azúcar granulada\n- 3/4 de taza de cacao en polvo\n- 1 y 1/2 cucharaditas de levadura en polvo\n- 1 y 1/2 cucharaditas de bicarbonato de sodio\n- 1 cucharadita de sal\n- 2 huevos\n- 1 taza de leche\n- 1/2 taza de aceite vegetal\n- 2 cucharaditas de extracto de vainilla\n- 1 taza de agua caliente\n\nPreparación:\n1. Precalentar el horno a 180°C y engrasar dos moldes para pastel de 20 cm de diámetro.\n2. En un bol grande tamizar mezclando bien la harina, el cacao en polvo, la levadura en polvo, el bicarbonato de sodio y la sal.\n3. En otro bol, batir los huevos, el azúcar, la leche, el aceite y el extracto de vainilla hasta formar una masa uniforme.\n4. Mezclar bien los ingredientes húmedos con los secos.\n5. Incorporar el agua caliente y mezclar nuevamente.\n6. Verter la masa en los moldes y hornear 30-35 minutos, o hasta que un palillo insertado en el centro salga limpio.\n7. Retirar del horno, dejar que se enfríen unos minutos y luego transferir a una rejilla.\n8. En una cacerola calentar la crema de leche (nata) sin que llegue a hervir.\n9. Retirar del fuego y agregar el chocolate picado.\n10. Revolver hasta que la mezcla esté suave.\n11. En un bol, batir la mantequilla con el azúcar glass y el extracto de vainilla hasta obtener una crema suave.\n12. Agregar la mezcla de chocolate derretido y batir hasta que la cobertura esté bien combinada.', 12, 30, 'ph-fork-knife'),
(8, 3, 'Pastel de Chocolate', 'pastel', 2, 30, 'ph-fork-knife'),
(9, 3, 'Pollo apanado ', '- 2 pechugas de pollo\n- 1 cebolla\n- Sal al gusto\nLuego mezclas todo y lo pones al horno.', 2, 30, 'ph-fork-knife');
